// // This module implements a 4-bit synchronous up counter with a synchronous reset.
module DownCounter4Bit (
    input clk,
    input reset,
    output reg [3:0] q
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 4'b0000;
        else
            q <= q - 1;
    end
endmodule
